// Easy WMS Webhook — Map & Validate
// Iterates despachos[], builds orders[] and packages[] for batch upsert

const OPERATOR_ID = '92dc5797-047d-458d-bbdb-63f18c0dd1e7'; // Musan
const TENANT_CLIENT_ID = 'ea9cf587-a031-4e71-b872-c5829f0536f3';        // easy-webhook tenant_clients row
const RETAILER_NAME = 'Easy';
const IMPORTED_VIA = 'API';

const body = $input.first().json.body;
const evento = body.evento || '';
const despachos = body.despachos || [];

if (despachos.length === 0) {
  console.warn('[Easy WMS] Empty despachos array. evento:', evento);
  return [{ json: {
    orders: [],
    packages: [],
    despachos_count: 0,
    orders_count: 0,
    packages_count: 0,
    warnings: ['Empty despachos array'],
    evento,
    operator_id: OPERATOR_ID,
    tenant_client_id: TENANT_CLIENT_ID
  }}];
}

function cleanPhone(phone) {
  if (!phone) return '';
  let cleaned = phone.replace(/[\s\-\.\(\)]/g, '');
  if (/^9\d{8}$/.test(cleaned)) cleaned = '+56' + cleaned;
  if (/^569\d{8}$/.test(cleaned)) cleaned = '+' + cleaned;
  return cleaned;
}

function parseDeliveryDate(despacho) {
  const fc = (despacho.fecha_compromiso || '').trim();
  if (fc && /^\d{4}-\d{2}-\d{2}$/.test(fc)) return fc;
  const fca = (despacho.fecha_carga || '').trim();
  if (fca && /^\d{4}-\d{2}-\d{2}$/.test(fca)) return fca;
  throw new Error('Missing valid delivery date for entrega ' + despacho.entrega + '. fecha_compromiso=' + fc + ', fecha_carga=' + fca);
}

const ordersMap = new Map(); // entrega -> order object
const packages = [];
const warnings = [];
const now = new Date().toISOString();

for (const despacho of despachos) {
  const entrega = (despacho.entrega || '').trim();
  if (!entrega) {
    warnings.push('Skipped despacho with missing entrega: ' + JSON.stringify(despacho).substring(0, 100));
    continue;
  }

  let deliveryDate;
  try {
    deliveryDate = parseDeliveryDate(despacho);
  } catch (e) {
    warnings.push(e.message);
    continue;
  }

  const customerPhone = cleanPhone(despacho.cliente_telefono || '');

  if (!ordersMap.has(entrega)) {
    ordersMap.set(entrega, {
      operator_id: OPERATOR_ID,
      order_number: entrega,
      external_load_id: despacho.id_carga || null,
      delivery_date: deliveryDate,
      delivery_address: despacho.direccion || '',
      comuna: despacho.comuna || '',
      customer_name: despacho.cliente_nombre || '',
      customer_phone: customerPhone,
      retailer_name: RETAILER_NAME,
      imported_via: IMPORTED_VIA,
      tenant_client_id: TENANT_CLIENT_ID,
      imported_at: now,
      raw_data: despacho
    });
  }

  const items = despacho.items || [];
  if (items.length === 0) {
    warnings.push('Despacho ' + entrega + ' has no items — order will be upserted but no packages');
  }

  for (const item of items) {
    const carton = (item.carton || '').trim();
    if (!carton) {
      warnings.push('Skipped item with missing carton in despacho ' + entrega);
      continue;
    }
    const bultos = Math.round(parseFloat(item.bultos) || 1) || 1;
    packages.push({
      operator_id: OPERATOR_ID,
      order_number: entrega, // used to link to order_id after upsert
      label: carton,
      declared_box_count: bultos,
      sku_items: [{
        sku: item.sku || '',
        description: item.descripcion || '',
        quantity: parseInt(item.cantidad, 10) || 1,
        codigo_barra: item.codigo_barra || '',
        mt3: item.mt3 || ''
      }],
      raw_data: item
    });
  }
}

const orders = Array.from(ordersMap.values());

if (orders.length === 0) {
  throw new Error('No valid orders extracted from ' + despachos.length + ' despachos. Warnings: ' + warnings.join('; '));
}

return [{ json: {
  orders,
  packages,
  despachos_count: despachos.length,
  orders_count: orders.length,
  packages_count: packages.length,
  warnings,
  evento,
  id_carga: despachos[0].id_carga || 'unknown',
  fecha_carga: despachos[0].fecha_carga || new Date().toISOString().split('T')[0],
  operator_id: OPERATOR_ID,
  tenant_client_id: TENANT_CLIENT_ID,
  raw_body: body
}}];

// Map order_number -> order_id from UPSERT Orders response
const orderItems = $input.all();
const orders = orderItems.map(item => item.json);
const packages = $('Map & Validate').first().json.packages;

const orderIds = {};
for (const o of orders) {
  if (o.order_number && o.id) {
    orderIds[o.order_number] = o.id;
  }
}

const packageBodies = packages
  .filter(p => {
    if (!orderIds[p.order_number]) {
      console.warn('[Easy WMS] No order_id found for package label=' + p.label + ' order_number=' + p.order_number);
      return false;
    }
    return true;
  })
  .map(p => ({
    operator_id: p.operator_id,
    order_id: orderIds[p.order_number],
    label: p.label,
    sku_items: p.sku_items,
    declared_box_count: p.declared_box_count,
    raw_data: p.raw_data
  }));

return [{ json: {
  packages: packageBodies,
  orders_upserted: orders.length,
  packages_count: packageBodies.length
}}];

// Prepare job completion data
const mapData = $('Map & Validate').first().json;
const linkData = $('Link Packages').first().json;
const jobId = $('Create Job Record').first().json.id;

// Check if package upsert had errors (continueOnFail=true may return error object)
let packagesError = null;
try {
  const pkgResp = $('UPSERT Packages').first();
  if (pkgResp && pkgResp.json && pkgResp.json.error) {
    packagesError = pkgResp.json.error;
  }
} catch(e) {
  packagesError = e.message;
}

// Check storage upload error
let storageError = null;
try {
  const storageResp = $('Upload Raw Payload').first();
  if (storageResp && storageResp.json && storageResp.json.error) {
    storageError = storageResp.json.error;
  }
} catch(e) {
  storageError = e.message;
}

return [{ json: {
  job_id: jobId,
  patch_body: {
    status: 'completed',
    completed_at: new Date().toISOString(),
    result: {
      evento: mapData.evento,
      id_carga: mapData.id_carga,
      despachos_count: mapData.despachos_count,
      orders_upserted: linkData.orders_upserted,
      packages_upserted: linkData.packages_count,
      warnings: mapData.warnings || [],
      packages_error: packagesError,
      storage_error: storageError
    }
  }
}}];

// Extract error info and job_id for failure handler
const error = $input.first().json;
let jobId = null;
try {
  const jobResp = $('Create Job Record').first();
  if (jobResp && jobResp.json) {
    jobId = jobResp.json.id || null;
  }
} catch(e) {
  // Create Job Record may not have run yet
}

const errorMessage = String(error.message || error.description || JSON.stringify(error)).substring(0, 1000);

return [{ json: {
  job_id: jobId || 'null',
  patch_body: {
    status: 'failed',
    completed_at: new Date().toISOString(),
    error_message: errorMessage
  }
}}];
